const item = $input.first();
const ct = item.json.canonical_ticket;
const text = (ct.subject + ' ' + ct.body).toLowerCase();

// Priority Rules for Uzum Ecosystem
const rules = [
  { 
    intent: 'access_issue', 
    regex: /\b(403|401|login|password|access|denied|portal|kabinet|kirish|parol|vaxod|dostup|forbidden)\b/, 
    severity: 'high', 
    score: 0.95 
  },
  { 
    intent: 'payment_issue', 
    regex: /\b(payment|to'lov|oplat|o'tkazma|transak|card|karta|uzcard|humo|click|payme)\b/, 
    severity: 'critical', 
    score: 0.9 
  },
  { 
    intent: 'security_alert', 
    regex: /\b(security|xavfsizlik|hacker|attack|virus|hack|fishing|vzlom)\b/, 
    severity: 'critical', 
    score: 1.0 
  },
  { 
    intent: 'network_issue', 
    regex: /\b(internet|network|tarmoq|connect|sechenie|vpn|slow|sekin|medlenno)\b/, 
    severity: 'medium', 
    score: 0.85 
  }
];

let detectedIntent = 'general_inquiry';
let detectedSeverity = ct.severity || 'medium';
let ruleConfidence = 0.5;

for (const rule of rules) {
  if (rule.regex.test(text)) {
    detectedIntent = rule.intent;
    detectedSeverity = rule.severity;
    ruleConfidence = rule.score;
    // Boost severity if it's a Merchant specific issue
    if (text.includes('merchant') || text.includes('portal') || text.includes('tadbirkor')) {
        detectedSeverity = (detectedSeverity === 'critical') ? 'critical' : 'high';
    }
    break;
  }
}

return [{
  json: {
    ...item.json,
    canonical_ticket: {
      ...ct,
      rule_engine: {
        intent: detectedIntent,
        severity: detectedSeverity,
        confidence: ruleConfidence,
        detected_at: new Date().toISOString(),
        engine_version: "2.1.0-enterprise"
      },
      data_integrity: {
        ...ct.data_integrity,
        last_modified: Date.now(),
        modification_count: (ct.data_integrity?.modification_count || 0) + 1
      }
    }
  }
}];

/**
 * REVENANT ENTERPRISE: Rule-Based Severity Classifier V22
 * Logic: Multi-factor weighted heuristic engine.
 */
const item = $input.first();
const ct = item.json.canonical_ticket || item.json;
const text = (ct.subject + ' ' + ct.body).toLowerCase();
const features = ct.text_features || {};

// 1. Scoring Matrix (Enterprise Weights)
const scores = { critical: 0, high: 0, medium: 0, low: 0 };

const WEIGHTS = {
  CRITICAL_INDICATOR: 3.5,
  HIGH_INDICATOR: 2.0,
  ERROR_CODE_MATCH: 1.5,
  INTENT_ESCALATION: 2.5,
  LENGTH_PENALTY: 1.0
};

// 2. High-Fidelity Pattern Matching
const patterns = {
  critical: /\b(outage|down|breach|loss|emergency|ishlamayapti|отключен|критическая)\b/i,
  high: /\b(failed|cannot|unable|error|failed|urgent|tezda|сброс|ошибка)\b/i,
  technical_errors: /error\s+(403|500|502|503|401)|timeout|database/i
};

// 3. Execution Logic
if (patterns.critical.test(text)) scores.critical += WEIGHTS.CRITICAL_INDICATOR;
if (patterns.high.test(text)) scores.high += WEIGHTS.HIGH_INDICATOR;
if (patterns.technical_errors.test(text)) scores.high += WEIGHTS.ERROR_CODE_MATCH;

// Cross-reference Text Features
if (features.has_critical) scores.critical += 2;
if (features.has_error_code) scores.high += 1.5;

// 4. Intent-Aware Escalation (Cross-Node Intelligence)
if (ct.rule_engine?.intent === 'access_issue' && text.includes('merchant')) {
    scores.high += WEIGHTS.INTENT_ESCALATION;
}

// 5. Deterministic Severity Selection
const maxScore = Math.max(scores.critical, scores.high, scores.medium, scores.low);
let finalSeverity = 'medium';

if (scores.critical >= 3) finalSeverity = 'critical';
else if (scores.high >= 2) finalSeverity = 'high';
else if (scores.medium >= 1) finalSeverity = 'medium';
else finalSeverity = 'low';

const confidence = Math.min(0.98, 0.4 + (maxScore / 10));

return [{
  json: {
    ...item.json,
    rule_based_severity: {
      severity: finalSeverity,
      confidence: parseFloat(confidence.toFixed(2)),
      scores: scores,
      calculated_at: new Date().toISOString()
    },
    canonical_ticket: {
      ...ct,
      rule_based_severity: {
        severity: finalSeverity,
        confidence: parseFloat(confidence.toFixed(2)),
        scores: scores
      }
    }
  }
}];

// NODE: Text Feature Engineering - V31-F1 (Hardened)
// CAPABILITY: Deterministic Intent & Entity Extraction (Upgraded for P2P)
// CONSTITUTION: Law 1.2 (Enrichment) & Law 3 (Severity Logic)

const items = $input.all();
const returnData = [];

// HELPER: Strict Uzbek Phone Number Extraction (V31-F1)
function extractP2PPhone(text) {
    if (!text) return null;
    const candidateRegex = /(\+?\d[\d\s\-()]{6,20}\d)/g;
    const candidates = text.match(candidateRegex) || [];

    for (const raw of candidates) {
        const digitsOnly = raw.replace(/\D/g, '');
        if (digitsOnly.length === 12 && digitsOnly.startsWith('998')) return digitsOnly;
        if (digitsOnly.length === 9) return '998' + digitsOnly; // Auto-prefix
    }
    return null;
}

for (const item of items) {
    const inputData = item.json;
    const ct = inputData.canonical_ticket || {};

    // 1. TEXT PREPARATION
    const subject = (ct.subject || '').toString().toLowerCase();
    const body = (ct.body || '').toString().toLowerCase();
    const text = `${subject} ${body}`;

    // 2. FEATURE EXTRACTION (REGEX - The "Eyes")
    const features = {
        has_account_number: /\b\d{16,20}\b/.test(text),
        has_phone_number: /\+998\d{9}/.test(text),
        has_card_number: /\b8600\d{12}\b/.test(text),
        has_crypto_terms: /\b(crypto|bitcoin|usdt|binance)\b/.test(text),
        has_urgent_keywords: /\b(immediately|asap|urgent|tezda|fast)\b/.test(text),
        has_security_terms: /\b(hack|stolen|fraud|replay|attack)\b/.test(text)
    };

    // 3. DETERMINISTIC INTENT CLASSIFICATION
    // Scoring matrix includes the new V31-F1 P2P_TRANSFER intent
    const intents = {
        "FRAUD_REPORT": ["scam", "fraud", "hacked", "stolen", "o'girlangan", "firibgar"],
        "CARD_BLOCK": ["block", "freeze", "lost card", "yo'qolgan", "bloklash", "stop"],
        "TRANSFER_ISSUE": ["transfer", "sent", "money", "pul", "o'tkazma", "yetib bormadi", "pending"],
        "BALANCE_INQUIRY": ["balance", "balans", "qancha", "how much", "qolgan"],
        "SECURITY_ALERT": ["replay", "attack", "injection", "vulnerability", "test"],
        "P2P_TRANSFER": ["yubor", "o'tkaz", "tashla", "perevod", "send", "pul yuborish"] ,
      "MERCHANT_CHECKOUT": ["pay to", "checkout", "scan qr", "makro", "korzinka", "merchant", "sotib", "to'lash"]
    };

    let detectedIntent = "GENERAL_INQUIRY";
    let maxScore = 0;

    Object.entries(intents).forEach(([intent, keywords]) => {
        const matchCount = keywords.reduce((acc, kw) => acc + (text.includes(kw) ? 1 : 0), 0);
        if (matchCount > maxScore) {
            maxScore = matchCount;
            detectedIntent = intent;
        }
    });

    // V31-F1: Extract Target Phone if Intent is P2P_TRANSFER
    if (detectedIntent === 'P2P_TRANSFER') {
        features.extracted_p2p_phone = extractP2PPhone(text);
    }

    // 4. SEVERITY CALCULATION (Constitution Law 3)
    let severity = "low";
    const amount = ct.transaction_amount || inputData.transaction_amount || 0;

    if (detectedIntent === "SECURITY_ALERT" || detectedIntent === "FRAUD_REPORT") {
        severity = "critical";
    } else if (detectedIntent === "CARD_BLOCK") {
        severity = "high";
    } else if (amount > 10000 || features.has_urgent_keywords) {
        severity = "high"; 
    } else if (detectedIntent === "TRANSFER_ISSUE") {
        severity = "medium";
    }

    // 5. CONSTRUCT RULE ENGINE RESULT
    const rule_engine = {
        intent: detectedIntent,
        confidence: maxScore > 0 ? 1.0 : 0.5, 
        severity: severity,
        detected_at: new Date().toISOString(),
        engine_version: "31.1.0-hardened"
    };

    // 6. OUTPUT & ENRICHMENT
    returnData.push({
        json: {
            ...inputData, 

            canonical_ticket: {
                ...ct,
                text_features: features, 
                rule_engine: rule_engine,
                severity: severity, 
                rule_based_intent: detectedIntent,
                classification: {
                    category: detectedIntent,
                    source: "DETERMINISTIC_ENGINE_V31"
                }
            },

            // Expose for Logic Gates & Switch Nodes
            rule_based_intent: detectedIntent,
            rule_based_severity: severity
        }
    });
}

return returnData;

/**
 * REVENANT ENTERPRISE: Pre-Fusion Normalizer V22
 * Logic: Conflict resolution & provenance stabilization.
 */
const item = $input.first();
const ct = item.json.canonical_ticket;

// 1. HARD VALIDATION: Fail-Fast for Data Integrity
if (!ct.rule_engine || !ct.rule_based_severity) {
  throw new Error(`INTEGRITY_VIOLATION: Missing intelligence inputs in trace ${ct.trace_id}`);
}

// 2. CONFLICT RESOLUTION (Expert Logic)
// If rule-based severity is 'critical' but engine says 'medium', we escalate to be safe.
const engineSev = ct.rule_engine.severity;
const ruleSev = ct.rule_based_severity.severity;

const SEVERITY_RANK = { critical: 4, high: 3, medium: 2, low: 1 };

const resolvedSeverity = (SEVERITY_RANK[ruleSev] >= SEVERITY_RANK[engineSev]) 
    ? ruleSev 
    : engineSev;

// 3. CONFIDENCE AGGREGATION
const normalizedConfidence = (ct.rule_engine.confidence + ct.rule_based_severity.confidence) / 2;

// 4. ENTERPRISE CLASSIFICATION OBJECT
const classification = {
  intent: ct.rule_engine.intent,
  severity: resolvedSeverity,
  confidence: parseFloat(normalizedConfidence.toFixed(2)),
  source: "hybrid_fusion_engine_v22",
  normalized_at: new Date().toISOString(),
  // EXPLAINABLE AI: Provenance maintains the "Why"
  provenance: {
    intent_source: "rule_engine_v21",
    severity_strategy: (ruleSev !== engineSev) ? "escalated_by_rule" : "consensus",
    raw_scores: {
      engine: engineSev,
      rules: ruleSev
    }
  }
};

// 5. IMMUTABLE UPDATE
return [{
  json: {
    canonical_ticket: {
      ...ct,
      classification: classification,
      data_integrity: {
        ...ct.data_integrity,
        last_modified: Date.now(),
        modification_count: (ct.data_integrity?.modification_count || 0) + 1,
        classification_normalized: true
      }
    }
  }
}];

/**
 * @file Business Impact & ROI Calculator
 * @version 2.1.0
 * @description Calculates financial impact and efficiency gains for automated ticket resolution.
 */

// 1. Constants & Default Configuration (Hardened)
const DEFAULTS = {
    COST_CONFIG: {
        agent_hourly_rate: 50000,
        manual_ticket_cost: 12500,
        ai_processing_cost: 2500,
        avg_resolution_time_mins: 15
    },
    CURRENCY: 'UZS'
};

try {
    const item = $input.first();
    const ct = item.json.canonical_ticket || {};

    // 2. Defensive Configuration Loading
    // Hierarchy: Workflow Config > Ticket Meta > Global Defaults
    const config = {
        ...DEFAULTS.COST_CONFIG,
        ...(ct.workflow_metadata?.config?.cost_uzs || {})
    };

    // 3. Extraction & Validation
    const isAutoResolved = ct.ticket_status === 'auto_resolved';
    const aiCost = Number(config.ai_processing_cost) || 0;
    const manualCost = Number(config.manual_ticket_cost) || 0;

    // 4. Core Logic: Financial Impact
    // Enterprise Standard: We calculate Gross Savings before ROI
    const grossSavings = isAutoResolved ? Math.max(0, manualCost - aiCost) : 0;

    // Prevent Division by Zero and handle ROI as a Ratio
    const roiPercentage = (isAutoResolved && aiCost > 0) 
        ? ((manualCost - aiCost) / aiCost) * 100 
        : 0;

    // 5. Build Structured Response
    return [{
        json: {
            ...item.json, // Preserve original root data
            canonical_ticket: {
                ...ct,
                business_impact: {
                    metrics: {
                        ai_cost_uzs: aiCost,
                        manual_cost_uzs: manualCost,
                        cost_saved_uzs: grossSavings,
                        roi_percent: parseFloat(roiPercentage.toFixed(2)),
                        time_saved_minutes: isAutoResolved ? config.avg_resolution_time_mins : 0
                    },
                    metadata: {
                        calculation_timestamp: new Date().toISOString(),
                        currency: DEFAULTS.CURRENCY,
                        config_source: ct.workflow_metadata?.config?.cost_uzs ? 'dynamic_override' : 'system_default',
                        version: "2.1.0"
                    }
                },
                data_integrity: {
                    ...ct.data_integrity,
                    last_modified: Date.now(),
                    modification_count: (ct.data_integrity?.modification_count || 0) + 1,
                    trace_id: ct.workflow_metadata?.trace_id || 'N/A'
                }
            }
        }
    }];

} catch (error) {
    // 6. Enterprise Error Handling
    // Instead of crashing, we return the item with an error flag for the next node to handle
    return [{
        json: {
            ...$input.first().json,
            error: {
                message: "Business Impact Calculation Failed",
                details: error.message,
                context: "impact_calculator_node"
            }
        }
    }];
}

/**
 * @file Uzbekistan SLA Engine
 * @version 2.1.0
 * @author Senior Systems Architect
 */

const item = $input.first();
const ct = item.json.canonical_ticket || {};

// 1. Immutable Time References
// Use the original webhook arrival time for SLA, not the current execution time
const referenceTime = new Date(ct.webhook_received_at || Date.now()).getTime();
const currentTime = Date.now();

// 2. Localization Logic
// We use Intl to handle Tashkent time without manual millisecond math
const tashkentTimeStr = new Intl.DateTimeFormat('en-US', {
  timeZone: 'Asia/Tashkent',
  hour12: false,
  weekday: 'long',
  year: 'numeric',
  month: 'numeric',
  day: 'numeric',
  hour: 'numeric',
  minute: 'numeric',
  second: 'numeric'
}).format(new Date(currentTime));

// Parse the formatted string to get clean components
const dayOfWeek = new Intl.DateTimeFormat('en-US', { timeZone: 'Asia/Tashkent', weekday: 'long' }).format(currentTime);
const hourTJS = parseInt(new Intl.DateTimeFormat('en-US', { timeZone: 'Asia/Tashkent', hour: 'numeric', hour12: false }).format(currentTime));

// 3. Business Logic Gates
const slaConfig = ct.workflow_metadata?.config?.uzbekistan_sla || {};
const isWeekend = ['Saturday', 'Sunday'].includes(dayOfWeek);
const isBusinessHours = !isWeekend && (hourTJS >= 9 && hourTJS < 18);

// 4. Threshold & Multiplier Resolution
const severity = ct.classification?.severity || 'medium';
const baseThresholds = slaConfig.thresholds_ms || {
  critical: 1800000, 
  high: 7200000, 
  medium: 28800000, 
  low: 86400000
};

const multiplier = isBusinessHours ? 1 : (slaConfig.after_hours_multiplier || 1.5);
const resolvedThreshold = (baseThresholds[severity] || baseThresholds.medium) * multiplier;

// 5. Performance Calculation
const totalProcessingMs = currentTime - referenceTime;
const deadlineTime = referenceTime + resolvedThreshold;
const isBreached = totalProcessingMs > resolvedThreshold;

// 6. Breach Classification (Categorical Analysis)
const getBreachLevel = (ms) => {
  if (ms <= 0) return 'none';
  if (ms > 3600000) return 'critical'; // > 1 hour late
  if (ms > 900000) return 'major';    // > 15 mins late
  return 'minor';
};



return [{
  json: {
    ...item.json,
    canonical_ticket: {
      ...ct,
      performance_metrics: {
        total_processing_ms: totalProcessingMs,
        meets_sla: !isBreached,
        sla_threshold_ms: resolvedThreshold,
        sla_breach_level: getBreachLevel(totalProcessingMs - resolvedThreshold),
        sla_breach_ms: isBreached ? (totalProcessingMs - resolvedThreshold) : 0,
        deadline_iso: new Date(deadlineTime).toISOString(),
        context: {
          tashkent_now: tashkentTimeStr,
          day_of_week: dayOfWeek,
          is_business_hours: isBusinessHours,
          applied_multiplier: multiplier,
          severity_used: severity
        }
      },
      data_integrity: {
        ...ct.data_integrity,
        last_modified: Date.now(),
        modification_count: (ct.data_integrity?.modification_count || 0) + 1
      }
    }
  }
}];

// Language Detection Engine - V30 (Alignment Table Mapper)
const item = $input.first();
const ct = item.json.canonical_ticket || {};
const text = ((ct.subject || '') + ' ' + (ct.body || '')).trim().toLowerCase();

if (!text) {
    return [{ json: { ...item.json, language_analysis: { detected: 'unknown', status: 'PENDING_TRANSCRIPTION' } } }];
}

// 1. SCORING
