// This strictly integrates your 4 original nodes without simplifying the logic.

const crypto = require('crypto');
const input = $json;

// ==========================================
// STAGE 1: Memory Ingress Normalizer Logic
// ==========================================

// 1. Assert State Integrity (Safety Kill-switch)
if (input.state === 'pending' || !input.consumed) {
  throw new Error("MEMORY_INGRESS_REJECTED: Only terminal, consumed states can be remembered.");
}

// 2. Normalize Semantic Payload
let normalized_approval = input.validated_approval;
if (typeof normalized_approval === 'string') {
  try {
    normalized_approval = JSON.parse(normalized_approval);
  } catch (e) {
    console.error("Failed to parse validated_approval, keeping as is.");
  }
}

// 3. Construct the BLOCK 6 Clean Object (Intermediate State 1)
const stage1_output = {
  identity: {
    approval_id: input.approval_id,
    trace_id: input.trace_id,
    user_id: input.approval_request?.user_id || "SYSTEM_USER" // Fallback if missing
  },
  semantics: {
    decision: input.decision,
    action: normalized_approval?.action || "UNKNOWN",
    validated_approval: normalized_approval,
    channel: input.selected_channel
  },
  integrity: {
    block_5_hash: input.block_5_seal_hash,
    advisory_hash: input.advisory_hash
  },
  temporal: {
    occurred_at: input.consumed_at,
    ingested_at: new Date().toISOString()
  },
  raw_context: input // Kept for safety
};

// ==========================================
// STAGE 2: Memory Identity Generator Logic
// ==========================================

const { identity, semantics, integrity } = stage1_output;

// Build canonical string for hashing
const canonicalString = `${identity.approval_id}:${identity.trace_id}:${semantics.decision}:${semantics.validated_approval.approver_role}:${integrity.block_5_hash}`;

const memoryIdHash = crypto
  .createHash('sha256')
  .update(canonicalString, 'utf8')
  .digest('hex');

const stage2_output = {
    ...stage1_output,
    memory_id_hash: memoryIdHash,
    memory_identity_version: 'v1'
};

// ==========================================
// STAGE 3: Scope Resolver Logic
// ==========================================

const approverRole = stage2_output.semantics.validated_approval.approver_role;
const userId = stage2_output.identity.user_id;
const traceId = stage2_output.identity.trace_id;

let scopeLevel;
let scopeId;

if (approverRole === 'system_bot' || approverRole === 'risk_officer') {
  scopeLevel = 'global';
  scopeId = 'GLOBAL';
} else if (userId && userId !== 'SYSTEM_USER') {
  scopeLevel = 'user';
  scopeId = userId;
} else {
  scopeLevel = 'session';
  scopeId = traceId;
}

const stage3_output = {
  ...stage2_output,
  scope_level: scopeLevel,
  scope_id: scopeId
};

// ==========================================
// STAGE 4: Memory Retrieval Prep Logic
// ==========================================

// Construct the string the AI will actually "search" by
const searchQuery = `Action: ${stage3_output.semantics.action} | Decision: ${stage3_output.semantics.decision} | Role: ${stage3_output.semantics.validated_approval.approver_role} | Reason: ${stage3_output.semantics.validated_approval.reason}`;

// Final Return
return {
  ...stage3_output,
  search_query: searchQuery
};

// BANK-GRADE CONTEXT COMPACTOR & CACHE LAYER
const items = $input.all()
  .map(item => item.json)
  .filter(m => Object.keys(m).length > 0 && m.final_score !== undefined);

if (items.length === 0) {
  return { 
    memory_context: "RECALL_MODE: NEW_IDENTITY | No historical precedents found in vault.", 
    memory_hits: [],
    is_cached: false
  };
}

// 1. RANKING: Sort by Decayed Final Score (Roadmap Item: Confidence Decay)
const ranked = items.sort((a, b) => b.final_score - a.final_score).slice(0, 3);

// 2. CACHE LAYER: Detect "Hot" Memories (Roadmap Item: Memory Cache)
// If similarity is >99% and it happened in the last 24 hours, flag as Cache Hit.
const perfectMatch = ranked.find(m => m.similarity >= 0.99 && m.recency_score < 24);
const recallMode = perfectMatch ? "HIGH_CONFIDENCE_CACHE_HIT" : "HEURISTIC_RECALL";

// 3. CONTEXT COMPACTOR: Summarize multiple matches into a single semantic block
const summary = ranked.map((m, idx) => {
  let details;
  try {
    details = typeof m.content === 'string' ? JSON.parse(m.content) : m.content;
  } catch (e) {
    details = { action: 'Unknown', decision: 'Unknown', reason: m.content };
  }

  return `[Precedent ${idx + 1}]: ${details.action} was ${details.decision} (Reason: ${details.reason}). Score: ${(m.final_score * 100).toFixed(1)}%`;
}).join(' | ');

return {
  memory_context: `RECALL_MODE: ${recallMode} | ${summary}`,
  memory_hits: ranked,
  is_cached: !!perfectMatch,
  top_score: ranked[0].final_score
};

