const transactionData = item.canonical_ticket || item;
const riskPrompt = "Evaluate this transaction for AML, Velocity, and Geo-Risk. Output strict JSON schema.";

const SCHEMA_ENFORCEMENT_PROMPT = `
You are a financial risk evaluation engine operating under strict regulatory oversight.

CRITICAL INSTRUCTIONS:
1. Analyse the provided transaction payload and risk prompt.
2. You MUST respond with ONLY a single, valid JSON object. No markdown, no prose, no explanation.
3. The JSON object MUST conform exactly to this schema:
   {
     "action":          "APPROVE" | "DENY",
     "confidence":      <number between 0.0 and 1.0>,
     "rules_triggered": ["<string>", ...]
   }

If you cannot make a determination, respond with:
  { "action": "DENY", "confidence": 1.0, "rules_triggered": ["INDETERMINATE"] }

Do NOT include any text outside the JSON object.
`.trim();

const messages = [
  { role: "system", content: SCHEMA_ENFORCEMENT_PROMPT },
  { role: "user", content: "RISK PROMPT:\n" + riskPrompt + "\n\nTRANSACTION PAYLOAD:\n" + JSON.stringify(transactionData, null, 2) }
];

return [{
  json: {
    ...item,
    _consensus_meta: { transactionData, riskPrompt },
    body_openai: {
      model: "openai/gpt-4o",
      temperature: 0,
      max_tokens: 512,
      response_format: { type: "json_object" },
      messages: messages
    },
    body_anthropic: {
      model: "anthropic/claude-3.5-sonnet",
      temperature: 0,
      max_tokens: 512,
      response_format: { type: "json_object" },
      messages: messages
    }
  }
}];

const crypto = require('crypto');

// Helpers
function parseAndValidate(raw) {
  if (!raw) return null;
  try {
    const cleaned = raw.replace(/^```(?:json)?\s*/i, "").replace(/\s*```\s*$/, "").trim();
    const parsed = JSON.parse(cleaned);
    if (typeof parsed !== "object" || !parsed || !parsed.action || typeof parsed.confidence !== "number" || !Array.isArray(parsed.rules_triggered)) return null;
    if (parsed.action !== "APPROVE" && parsed.action !== "DENY") return null;
    return {
      action: parsed.action,
      confidence: Math.min(1, Math.max(0, parsed.confidence)),
      rules_triggered: parsed.rules_triggered
    };
  } catch (e) { return null; }
}

function sha256Hex(data) {
  const canonical = JSON.stringify(data, Object.keys(data).sort());
  return crypto.createHash("sha256").update(canonical, "utf8").digest("hex");
}

// 1. Fetch data from all nodes seamlessly
const originalItem = $('Prep Consensus Payload').first().json;
const openaiEnv = $('LLM OpenRouter (OpenAI)').first().json;
const anthropicEnv = $('LLM OpenRouter (Anthropic)').first().json;

// 2. Extract contents and statuses
const openaiRawContent = openaiEnv?.choices?.[0]?.message?.content || null;
const anthropicRawContent = anthropicEnv?.choices?.[0]?.message?.content || null;

const oaiParsed = parseAndValidate(openaiRawContent);
const antParsed = parseAndValidate(anthropicRawContent);

const openaiOk = oaiParsed !== null;
const anthropicOk = antParsed !== null;

// 3. Consensus Logic
const bothApprove = openaiOk && anthropicOk && oaiParsed.action === "APPROVE" && antParsed.action === "APPROVE";
let consensus, reason;

if (bothApprove) {
  consensus = "APPROVED";
  reason = `Both providers independently approved. OpenAI confidence: ${oaiParsed.confidence}, Anthropic confidence: ${antParsed.confidence}.`;
} else if (!openaiOk && !anthropicOk) {
  consensus = "ESCALATE_TO_HUMAN";
  reason = "ESCALATED: Both providers failed schema validation or timed out.";
} else if (!openaiOk) {
  consensus = "ESCALATE_TO_HUMAN";
  reason = "ESCALATED: OpenAI failed schema validation or timed out.";
} else if (!anthropicOk) {
  consensus = "ESCALATE_TO_HUMAN";
  reason = "ESCALATED: Anthropic failed schema validation or timed out.";
} else {
  consensus = "ESCALATE_TO_HUMAN";
  reason = `ESCALATED: Disagreement detected. OpenAI=${oaiParsed?.action || "FAIL"}, Anthropic=${antParsed?.action || "FAIL"}.`;
}

// 4. Build WORM Audit Result
const result = {
  consensus,
  decided_at: new Date().toISOString(),
  audit_hash: "",
  openai: {
    action: openaiOk ? oaiParsed.action : "FAILED",
    confidence: openaiOk ? oaiParsed.confidence : null,
    rules_triggered: openaiOk ? oaiParsed.rules_triggered : null,
    provider_id: openaiEnv?.id || null
  },
  anthropic: {
    action: anthropicOk ? antParsed.action : "FAILED",
    confidence: anthropicOk ? antParsed.confidence : null,
    rules_triggered: anthropicOk ? antParsed.rules_triggered : null,
    provider_id: anthropicEnv?.id || null
  },
  reason
};

const auditPayload = {
  ...result,
  audit_hash: undefined,
  _raw_openai_envelope: openaiEnv,
  _raw_anthropic_envelope: anthropicEnv,
  _transaction_sha256: sha256Hex(originalItem._consensus_meta.transactionData)
};

result.audit_hash = sha256Hex(auditPayload);

// 5. Structure output exactly for downstream compatibility
const combinedRules = [...new Set([
  ...(result.openai.rules_triggered || []),
  ...(result.anthropic.rules_triggered || [])
])];

const minConfidence = Math.min(
  result.openai.confidence || 0, 
  result.anthropic.confidence || 0
);

const finalAdvisory = {
  action: result.consensus === "APPROVED" ? "APPROVE" : "DENY",
  confidence: minConfidence,
  rules_triggered: combinedRules,
  consensus_reason: result.reason
};

// Clean up prep fields
delete originalItem._consensus_meta;
delete originalItem.body_openai;
delete originalItem.body_anthropic;

return [{
  json: {
    ...originalItem,
    ai_consensus_audit: result,
    choices: [{
      message: {
        content: JSON.stringify(finalAdvisory)
      }
    }]
  }
}];

// ============================================================================
// REVENANT - PIIRedactor.js (n8n Native Version)
// Phase 4.1: Hybrid PII Redaction Engine
// ============================================================================

// ── Regex Patterns ──────────────────────────────────────────────────────────
const REGEX_PAN = /\b[3-6]\d{3}[-\s]?\d{4}[-\s]?\d{4}[-\s]?\d{1,7}\b/g;
const REGEX_IBAN = /\b([A-Z]{2})(\d{2})\s?([A-Z0-9]{4}\s?){1,7}([A-Z0-9]{1,4})\b/g;
const REGEX_EMAIL = /\b[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}\b/g;
const REGEX_PHONE = /(?<!\d)(\+?1?\s?)?(\(?\d{3}\)?[\s.\-]?)(\d{3}[\s.\-]?\d{4})(\s?(ext|x)\.?\s?\d{1,5})?(?!\d)/g;
const REGEX_SSN_HYPHEN = /\b(?!000|666|9\d{2})([0-8]\d{2})[-\s](?!00)(\d{2})[-\s](?!0000)(\d{4})\b/g;

const SSN_CONTEXT_TRIGGERS = [
  "ssn", "social security", "social sec", "tin", "taxpayer", 
  "itin", "national id", "nationalid", "national_id", "tax id", 
  "taxid", "sin", "nino", "national insurance"
];

// ── Validation Algorithms ───────────────────────────────────────────────────
function luhnCheck(raw) {
  const digits = raw.replace(/\D/g, "");
  if (digits.length < 13 || digits.length > 19) return false;
  let sum = 0;
  let double = false;
  for (let i = digits.length - 1; i >= 0; i--) {
    let digit = parseInt(digits[i], 10);
    if (double) {
      digit *= 2;
      if (digit > 9) digit -= 9;
    }
    sum += digit;
    double = !double;
  }
  return sum % 10 === 0;
}

function ibanCheck(raw) {
  const iban = raw.replace(/\s/g, "").toUpperCase();
  if (iban.length < 15 || iban.length > 34) return false;
  const rearranged = iban.slice(4) + iban.slice(0, 4);
  const numeric = rearranged.split("").map((ch) => {
    const code = ch.charCodeAt(0);
    return code >= 65 && code <= 90 ? (code - 55).toString() : ch;
  }).join("");

  let remainder = BigInt(0);
  const chunks = numeric.match(/.{1,9}/g) || [];
  for (const chunk of chunks) {
    let multiplier = BigInt(1);
    for(let i = 0; i < chunk.length; i++) multiplier *= BigInt(10);
    remainder = ((remainder * multiplier) + BigInt(chunk)) % BigInt(97);
  }
  return remainder === BigInt(1);
}

// ── Format-Preserving Masking Functions ─────────────────────────────────────
function maskPAN(pan) {
  const digits = pan.replace(/\D/g, "");
  const sep = pan.includes(" ") ? " " : pan.includes("-") ? "-" : "";
  const masked = digits.split("").map((d, i) => (i < 6 || i >= digits.length - 4) ? d : "*").join("");
  if (!sep) return masked;
  const groups = [];
  for (let i = 0; i < masked.length; i += 4) {
    groups.push(masked.slice(i, i + 4));
  }
  return groups.join(sep);
}

function maskIBAN(iban) {
  const spaces = [];
  const stripped = iban.split("").filter((ch, i) => {
    if (ch === " ") { spaces.push(i); return false; }
    return true;
  }).join("");
  const reveal_start = 4;
  const reveal_end = stripped.length - 4;
  const masked = stripped.split("").map((ch, i) => (i < reveal_start || i >= reveal_end) ? ch : "*").join("");
  let result = masked;
  let offset = 0;
  for (const pos of spaces) {
    result = result.slice(0, pos + offset) + " " + result.slice(pos + offset);
    offset++;
  }
  return result;
}

function maskEmail(email) {
  const atIdx = email.lastIndexOf("@");
  if (atIdx < 1) return "***@***.***";
  const local = email.slice(0, atIdx);
  const domain = email.slice(atIdx + 1);
  const maskedLocal = local[0] + "***";
  const dotIdx = domain.lastIndexOf(".");
  const tld = dotIdx >= 0 ? domain.slice(dotIdx) : "";
  const maskedDomain = "***" + tld;
  return `${maskedLocal}@${maskedDomain}`;
}

function maskPhone(phone) {
  const digits = phone.replace(/\D/g, "");
  const maskedDigits = digits.split("").map((d, i) => (i >= digits.length - 2 ? d : "*")).join("");
  let digitIndex = 0;
  return phone.split("").map((ch) => {
    if (/\d/.test(ch)) return maskedDigits[digitIndex++];
    return ch;
  }).join("");
}

function maskSSN(ssn) {
  const sep = ssn.includes("-") ? "-" : ssn.includes(" ") ? " " : "";
  const digits = ssn.replace(/\D/g, "");
  const masked = digits.split("").map((d, i) => (i >= digits.length - 4 ? d : "*")).join("");
  if (!sep) return masked;
  return `${masked.slice(0, 3)}${sep}${masked.slice(3, 5)}${sep}${masked.slice(5)}`;
}

// ── Core String Redaction Pipeline ──────────────────────────────────────────
function _redactString(input, opts, context = input) {
  let result = input;
  const counts = {};
  const increment = (type, n = 1) => { counts[type] = (counts[type] || 0) + n; };

  if (opts.redactCreditCards) {
    result = result.replace(REGEX_PAN, (match) => {
      if (!luhnCheck(match)) return match;
      increment("CREDIT_CARD_PAN");
      return maskPAN(match);
    });
    REGEX_PAN.lastIndex = 0;
  }

  if (opts.redactIBANs) {
    result = result.replace(REGEX_IBAN, (match) => {
      if (!ibanCheck(match)) return match;
      increment("IBAN");
      return maskIBAN(match);
    });
    REGEX_IBAN.lastIndex = 0;
  }

  if (opts.redactEmails) {
    result = result.replace(REGEX_EMAIL, (match) => {
      increment("EMAIL");
      return maskEmail(match);
    });
    REGEX_EMAIL.lastIndex = 0;
  }

  if (opts.redactPhones) {
    result = result.replace(REGEX_PHONE, (match) => {
      const digitCount = (match.match(/\d/g) || []).length;
      if (digitCount < 7) return match;
      increment("PHONE");
      return maskPhone(match);
    });
    REGEX_PHONE.lastIndex = 0;
  }

  if (opts.redactSSNs) {
    result = result.replace(REGEX_SSN_HYPHEN, (match) => {
      increment("SSN_NATIONAL_ID");
      return maskSSN(match);
    });
    REGEX_SSN_HYPHEN.lastIndex = 0;

    const contextLower = context.toLowerCase();
    const hasSSNContext = SSN_CONTEXT_TRIGGERS.some((t) => contextLower.includes(t));

    if (hasSSNContext) {
      result = result.replace(
        /(?<!\d)(?!000|666|9\d{2})([0-8]\d{2})(?!00)(\d{2})(?!0000)(\d{4})(?!\d)/g,
        (match) => {
          increment("SSN_NATIONAL_ID");
          return maskSSN(match);
        }
      );
    }
  }

  return { result, counts };
}

// ── Deep JSON Traversal ─────────────────────────────────────────────────────
function _traverseAndRedact(value, path, opts, events) {
  if (typeof value === "string") {
    const { result, counts } = _redactString(value, opts);
    for (const [type, count] of Object.entries(counts)) {
      if (count > 0) events.push({ type, path, count });
    }
    return result;
  }

  if (Array.isArray(value)) {
    return value.map((item, idx) => _traverseAndRedact(item, `${path}[${idx}]`, opts, events));
  }

  if (value !== null && typeof value === "object") {
    const sanitised = {};
    for (const [key, child] of Object.entries(value)) {
      sanitised[key] = _traverseAndRedact(child, path ? `${path}.${key}` : key, opts, events);
    }
    return sanitised;
  }

  return value;
}

// ── Public API Wrapper ──────────────────────────────────────────────────────
const DEFAULT_OPTIONS = {
  redactCreditCards: true,
  redactIBANs: true,
  redactEmails: true,
  redactPhones: true,
  redactSSNs: true,
};

function redactPayload(payload, options = {}) {
  const opts = { ...DEFAULT_OPTIONS, ...options };
  const events = [];
  const sanitised = _traverseAndRedact(payload, "(root)", opts, events);
  return {
    sanitised,
    report: {
      total_redactions: events.reduce((s, e) => s + e.count, 0),
      events,
      redacted_at: new Date().toISOString(),
    },
  };
}

// ─────────────────────────────────────────────────────────────────────────────
// SECTION 9 – n8n Execution Integration
// ─────────────────────────────────────────────────────────────────────────────
const items = $input.all();
const output = [];

for (const item of items) {
  // Clone original item state
  let finalItem = { ...item.json };

  if (finalItem.canonical_ticket) {
    // Deep redact canonical ticket payload
    const { sanitised, report } = redactPayload(finalItem.canonical_ticket);

    // Override with clean payload and attach WORM logging report
    finalItem.canonical_ticket = sanitised;
    finalItem.pii_audit_report = report;
  }

  output.push({ json: finalItem });
}

return output;

// ================================================================
// MasterRouter.js - n8n Code Node
// Phase 2 – Deterministic Router
// ================================================================
const CONFIG = {
  // Risk Score weights (must sum to 1)
  WEIGHTS: {
    amount: 0.40,
    geo: 0.25,
    velocity: 0.20,
    device: 0.15,
  },

// Amount risk: linear up to the hard block limit (50M UZS)
AMOUNT_MAX: 50000000,
// Geo mismatch: distance threshold in kilometres
GEO_MISMATCH_KM: 100,
GEO_MISMATCH_SCORE: 100,
// Velocity risk: max \"normal\" requests per hour
VELOCITY_MAX_PER_HOUR: 60,
// Ambiguity: required fields per intent
REQUIRED_FIELDS: {
  TRANSACTION: ['amount', 'destinationAccount'],
  PAYMENT_ISSUE: ['amount'],
  FAQ: ['message'],
  DEFAULT: [],
},
};

// --- Helpers ---

function haversineDistance(a, b) {
  const R = 6371; // Earth radius in km
  const dLat = ((b.lat - a.lat) * Math.PI) / 180;
  const dLon = ((b.lon - a.lon) * Math.PI) / 180;
  const lat1 = (a.lat * Math.PI) / 180;
  const lat2 = (b.lat * Math.PI) / 180;
  const sinDLat = Math.sin(dLat / 2);
  const sinDLon = Math.sin(dLon / 2);
  const aVal = sinDLat * sinDLat + Math.cos(lat1) * Math.cos(lat2) * sinDLon * sinDLon;
  const c = 2 * Math.atan2(Math.sqrt(aVal), Math.sqrt(1 - aVal));
  return R * c;
}

function amountRisk(amount) {
  return Math.min((amount / CONFIG.AMOUNT_MAX) * 100, 100);
}

function geoRisk(userLoc, deviceLoc) {
  if (!userLoc || !deviceLoc) return 0;
  const dist = haversineDistance(userLoc, deviceLoc);
  return dist > CONFIG.GEO_MISMATCH_KM ? CONFIG.GEO_MISMATCH_SCORE : 0;
}

function velocityRisk(recentCount) {
  return Math.min((recentCount / CONFIG.VELOCITY_MAX_PER_HOUR) * 100, 100);
}

function deviceRisk(trustScore) {
  return 100 - trustScore;
}

function calculateRiskScore(input) {
  const w = CONFIG.WEIGHTS;
  const score =
    w.amount * amountRisk(input.amount) +
    w.geo * geoRisk(input.userLocation, input.deviceLocation) +
    w.velocity * velocityRisk(input.recentRequestCount) +
    w.device * deviceRisk(input.deviceTrustScore);
  return Math.round(score);
}

function calculateAmbiguityScore(input) {
  const intentKey = (input.intent || '').toUpperCase();
  const required = CONFIG.REQUIRED_FIELDS[intentKey] || CONFIG.REQUIRED_FIELDS.DEFAULT;

  if (required.length === 0) return 0;

  let missingCount = 0;
  for (const field of required) {
    const value = input[field];
    if (field === 'amount') {
      if (!value || value <= 0) missingCount++;
    } else if (field === 'destinationAccount' || field === 'message') {
      if (!value || typeof value !== 'string' || value.trim() === '') missingCount++;
    }
  }

  return Math.round((missingCount / required.length) * 100);
}

function determineRoute(input) {
  const risk_score = calculateRiskScore(input);
  const ambiguity_score = calculateAmbiguityScore(input);
  const intentKey = (input.intent || '').toUpperCase();

  let route;

  if (ambiguity_score > 40) {
    route = 'CLARIFICATION_LOOP';
  } else if (intentKey === 'FAQ' && risk_score < 20) {
    route = 'FLOW_FAQ';
  } else if (risk_score > 80) {
    route = 'FLOW_SECURITY';
  } else if (intentKey === 'TRANSACTION' || intentKey === 'PAYMENT_ISSUE' || intentKey === 'TRANSFER') {
    route = 'FLOW_TRANSACTION';
  } else {
    route = 'FLOW_GENERAL';
  }

  return { route, risk_score, ambiguity_score };
}

// --- Execution Loop ---

const items = $input.all();
const output = [];

for (const item of items) {
  const ct = item.json.canonical_ticket || {};
  const meta = ct.metadata || {};

  // Safely map values from previous feature engineering & rule engines
  const safeInput = {
    amount: parseFloat(ct.transaction_amount || item.json.transaction_amount) || 0,
    userLocation: meta.userLocation,
    deviceLocation: meta.deviceLocation,
    recentRequestCount: parseInt(meta.recentRequestCount, 10) || 0,
    // Default device trust to 100 (trusted) if not strictly provided by WAF/webhook to avoid false-positives
    deviceTrustScore: meta.deviceTrustScore !== undefined ? Math.min(100, Math.max(0, parseFloat(meta.deviceTrustScore))) : 100,
    intent: ct.rule_engine?.intent || 'DEFAULT',
    // Use text features regex result as fallback for destination account mapping
    destinationAccount: meta.destinationAccount || (ct.text_features?.has_account_number ? "account_detected" : undefined),    
    message: `${ct.subject || ''} ${ct.body || ''}`.trim()
  };

  // Execute triage logic
  const decision = determineRoute(safeInput);

  output.push({
    json: {
      ...item.json,
      canonical_ticket: {
        ...ct,
        routing_decision: decision
      }
    }
  });
}

return output;

