        source_ip: sanitizeString(ip, 45),
        user_agent: sanitizeString(headers["user-agent"] || "unknown", 200)
    }
};

// ============================================================
// 5. OUTPUT (Unchanged Structural Integrity)
// ============================================================
return [{ 
