/**
 * Node: BLOCK 4.4 — DETERMINISTIC PROPOSAL BUILDER / PAYMENT SURFACE GENERATOR
 * Location: After "LLM Output Sanitizer" & before "Advisory Confidence Labeler".
 * Purpose: Strips operational authority from the LLM for deterministic-routing
 * intents. Handles P2P_TRANSFER and MERCHANT_CHECKOUT (Pay-by-Chat).
 *
 * CRITICAL: n8n cloud sandbox — no require('crypto'). All token encoding and
 * signing here is pure-JS bitwise arithmetic.
 */

const items = $input.all();

// ---------------------------------------------------------------------------
// Pure-JS Base64 encoder (no Buffer, no btoa, no crypto module)
// ---------------------------------------------------------------------------
function base64Encode(str) {
  const keyStr = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=';
  let output = '';
  let i = 0;

  while (i < str.length) {
    const chr1 = str.charCodeAt(i++);
    const chr2 = str.charCodeAt(i++); 
    const chr3 = str.charCodeAt(i++); 

    const enc1 = chr1 >> 2;
    const enc2 = ((chr1 & 3) << 4) | (isNaN(chr2) ? 0 : chr2 >> 4);
    const enc3 = isNaN(chr2) ? 64 : (((chr2 & 15) << 2) | (isNaN(chr3) ? 0 : chr3 >> 4));
    const enc4 = isNaN(chr3) ? 64 : (chr3 & 63);

    output += keyStr.charAt(enc1) + keyStr.charAt(enc2) + keyStr.charAt(enc3) + keyStr.charAt(enc4);
  }

  return output;
}

// Pure-JS 32-bit FNV-1a hash (Sandbox Safe)
function generatePureJSHash(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193);
  }
  return (hash >>> 0).toString(16);
}

for (const item of items) {
  const json = item.json;

  // Safe exit: no ticket at all -> pass through unchanged.
  if (!json.canonical_ticket) {
    continue;
  }

  const ticket = json.canonical_ticket;
  // Support both intent locations depending on how upstream nodes map it
  const intent = ticket.rule_engine?.intent || ticket.rule_based_intent;

  // Gate widened for F3: this node now handles P2P_TRANSFER and MERCHANT_CHECKOUT
  if (intent !== 'P2P_TRANSFER' && intent !== 'MERCHANT_CHECKOUT') {
    continue;
  }

  // Check for upstream security stops / validation errors
  if (json.validation_error || json.security_stop || json.blocked === true || json.advisory?.llm_status?.status === 'llm_failed_fallback') {
    continue;
  }

//=================================================================
  // BRANCH 1: P2P_TRANSFER (UPGRADED WITH STATELESS TOKEN & TELEGRAM BUTTON)
//=================================================================
  if (intent === 'P2P_TRANSFER') {
    const customer_email = ticket.customer_email;
