    const recipient = ticket.p2p_resolved_recipient;
    const amount = parseFloat(ticket.transaction_amount);

    if (!customer_email || !target_phone || !recipient || isNaN(amount)) continue;

    // 1. Generate Stateless Token for P2P Callback
    const tokenPayload = {
      target: target_phone,
      amount: amount,
      trace_id: ticket.trace_id,
      timestamp: Date.now()
    };
    const paymentToken = base64Encode(JSON.stringify(tokenPayload));
    const tokenSignature = generatePureJSHash(paymentToken);

    // 2. Build the Telegram Inline Button
    const telegramKeyboard = {
      inline_keyboard: [[
        {
          text: '✅ Tasdiqlash (Confirm Transfer)',
          callback_data: `CONFIRM_P2P|${paymentToken}|${tokenSignature}`
        }
      ]]
    };

    const deterministicProposal = {
      tool_name: "EXECUTE_P2P_TRANSFER",
      parameters: {
        source_email: String(customer_email),
        target_phone: String(target_phone),
        amount_uzs: amount
      },
      telegram_action: telegramKeyboard, // Injecting the button
      requires_approval: true
    };

    if (!json.advisory) json.advisory = {};
    if (!json.advisory.llm_output) json.advisory.llm_output = {};

    json.advisory.llm_output.transaction_proposal = deterministicProposal;
    json.advisory.llm_output.draft_customer_response =
      `Assalomu alaykum. Haqiqatdan ham ${amount} UZS mablag'ni ${recipient.legal_name} (${recipient.masked_account}) hisobiga o'tkazmoqchimisiz? Tasdiqlash uchun tugmani bosing.`;

    continue;
  }

//=================================================================
  // BRANCH 2: MERCHANT_CHECKOUT — NEW IN F3 (Pay-by-Chat)
  //=================================================================
  if (intent === 'MERCHANT_CHECKOUT') {
    const merchant = ticket.merchant_checkout;

    // Guard: must have passed Block 3.6 verification first.
