      continue;
    }

    const amount = Number(merchant.amount_locked);
    if (!Number.isFinite(amount) || amount <= 0) {
      continue;
    }

    // --- Stateless Payment Token: { merchant_id, amount, trace_id } -> base64 ---
    const tokenPayload = {
      merchant_id: merchant.merchant_id,
      amount: amount,
      trace_id: ticket.trace_id,
    };
    const tokenString = JSON.stringify(tokenPayload);
    const paymentToken = base64Encode(tokenString);

    // --- Pure-JS signature of the encoded token ---
    const tokenSignature = generatePureJSHash(paymentToken);

    // --- Deep link for native app handoff ---
    const deepLinkUrl = `revenant://pay?payload=${encodeURIComponent(paymentToken)}&sig=${encodeURIComponent(tokenSignature)}`;
