    // Build the fully deterministic payment surface proposal
    const merchantProposal = {
      tool_name: "CREATE_PAYMENT_SURFACE",
      rationale: "Deterministic payment surface generated from a verified, registry-locked merchant target.",
      parameters: {
        merchant_id: String(merchant.merchant_id),
