    };

    if (!json.advisory) json.advisory = {};
    if (!json.advisory.llm_output) json.advisory.llm_output = {};

    json.advisory.llm_output.transaction_proposal = merchantProposal;
    json.advisory.llm_output.draft_customer_response =
      `Assalomu alaykum. ${merchant.merchant_alias} uchun ${amount} UZS to'lovni tasdiqlaysizmi? Tasdiqlash uchun quyidagi tugmani bosing.`;

    continue;
  }
}

