function sanitizeAccountHolderName(rawName) {
  if (typeof rawName !== 'string' || rawName.length === 0) {
    return 'UNKNOWN_ACCOUNT_HOLDER';
  }

  let name = rawName;
  // Strip control characters & HTML
  name = name.replace(/[\u0000-\u001F\u007F-\u009F]/g, ' ');
  name = name.replace(/<[^>]*>/g, '');
  // Neutralize markdown & common injection words
  name = name.replace(/[*_`#\[\]()~>|]/g, '');
  name = name.replace(INJECTION_PATTERN, '');
  // Controller fallback: Strip anything non-alphanumeric as final sweep
  name = name.replace(/[^a-zA-Z0-9\s]/g, '');
  // Collapse whitespace and cap length
  name = name.replace(/\s{2,}/g, ' ').trim();

  return name.slice(0, HARD_NAME_LIMIT) || 'UNKNOWN_ACCOUNT_HOLDER';
}

function sanitizeMaskedCard(rawCard) {
  if (typeof rawCard !== 'string') return '';
  return rawCard.replace(/[^0-9*]/g, '').slice(0, 19);
